package com.example.nofiltercoffee; import android.os.*; import android.widget.*; import androidx.appcompat.app.*;
public class AboutActivity extends AppCompatActivity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.simple_page);findViewById(R.id.btnBack).setOnClickListener(v->finish());((TextView)findViewById(R.id.txtTitle)).setText("About No Filter");((TextView)findViewById(R.id.txtBody)).setText("No Filter Coffee is built around a simple idea: good coffee does not need noise.\n\nIt is a premium, modern coffee experience for people who want bold espresso, smooth iced lattes, matcha, bakery treats, desserts, and quick pick-up without unnecessary friction.\n\nThe app is designed for order-ahead convenience: choose your drink, customize it, earn Coffee Beans, apply vouchers, save cards, and pick up fresh.\n\nLife happens. Coffee helps. No Filter keeps it clean, fast, and worth coming back for.");}}
